import subprocess
from sys import platform

def convertDocument(input_file, output_file, output_format):
    if not input_file.endswith(('.docx', '.odt', '.txt')):
        raise ValueError("Unsupported file format for conversion")

    libreoffice_path = "/usr/bin/libreoffice"  # Default path on Linux
    if platform == "darwin":  # MacOS
        libreoffice_path = "/Applications/LibreOffice.app/Contents/MacOS/libreoffice"
    elif platform == "win32":
        libreoffice_path = "C:/Program Files (x86)/LibreOffice 7/program/libreoffice.exe"

    if output_format == 'pdf':
        command = f"{libreoffice_path} --headless --convert-to pdf {input_file}"
    elif output_format == 'jpg' or output_format == 'png' or output_format == 'jpeg':
        # Image conversion is not direct, using unoconv for image to pdf
        subprocess.run(f"unoconv -f pdf {input_file}", shell=True)
        command = f"{libreoffice_path} --headless --convert-to pdf output.pdf"
    else:
        raise ValueError("Unsupported output format")

    try:
        subprocess.run(command, check=True, shell=True)
        # Remove intermediate file
        if output_format == 'pdf' and input_file.endswith('.docx'):
            import os
            os.remove(input_file)
        elif output_format in ['jpg', 'png', 'jpeg']:
            import os
            os.remove('output.pdf')
    except subprocess.CalledProcessError:
        raise ValueError("Failed to convert document")

# Example usage
